// Generate weekly test — uses ONLY weekly pool (45 per subject)
export function getWeeklyTestQuestions(questionsPerSubject: number = 45): TestQuestion[] {
  const subjects = ["Botany", "Zoology", "Physics", "Chemistry"];
  const allQuestions: TestQuestion[] = [];
  subjects.forEach(subject => {
    const available = questionBank.filter(q => q.pool === "weekly" && q.subject === subject);
    const result: TestQuestion[] = [];
    if (available.length === 0) {
      // Fallback
      const fallback = questionBank.filter(q => q.subject === subject);
      while (result.length < questionsPerSubject) {
        result.push(...shuffleArray(fallback).slice(0, Math.min(questionsPerSubject - result.length, fallback.length)));
      }
    } else {
      while (result.length < questionsPerSubject) {
        result.push(...shuffleArray(available).slice(0, Math.min(questionsPerSubject - result.length, available.length)));
      }
    }
    allQuestions.push(...result);
  });
  return allQuestions.map((q, i) => ({ ...q, id: `${q.id}-wk-${i}` }));
}

